1	\chapter{Line bundles on schemes and the Picard group}
2	\label{chap:Picard_LineBundle}
3	
4	This chapter sets up the foundational Phase~B/C infrastructure: the type of \emph{line bundles} (invertible quasi-coherent sheaves) on a scheme $X$, the abelian-group structure under tensor product, and the pull-back functoriality. It is the smallest self-contained step toward the Picard scheme construction (Theorem~\ref{thm:Pic_representable}) and feeds Steps~2--6 of the Jacobian gap chain.
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $\Pic_{C/k}$ in later phases.
7	
8	\section{Definition}
9	
10	% NOTE: Iter-003 closed this sorry under a documented first-approximation:
11	% LineBundle X := CommRing.Pic Γ(X, ⊤) (the Picard group of the global-sections
12	% ring). This agrees with the true Pic(X) on affine schemes (Stacks 0AGS) and is
13	% a strict subgroup on non-affine schemes. The bespoke symmetric-monoidal
14	% definition below cannot currently be stated because Mathlib b80f227 lacks
15	% MonoidalCategory X.Modules. See AlgebraicJacobian/Picard/LineBundle.lean
16	% docstring and proof-journal/sessions/session_2/recommendations.md for the
17	% deferred-to-iter-004+ refinement plan.
18	\begin{definition}[Line bundle on a scheme]
19	  \label{def:Scheme_LineBundle}
20	  \lean{AlgebraicGeometry.Scheme.LineBundle}
21	  Let $X$ be a scheme. A \emph{line bundle} on $X$ is an invertible quasi-coherent $\mathcal O_X$-module: a sheaf $L \in X.\mathtt{Modules}$ that is quasi-coherent and locally free of rank $1$. Equivalently (Mathlib formulation): an object of $X.\mathtt{Modules}$ that is invertible with respect to the tensor product $- \otimes_{\mathcal O_X} -$ in the symmetric monoidal category $X.\mathtt{Modules}$.
22	\end{definition}
23	
24	\begin{remark}
25	  Mathlib has \lstinline{AlgebraicGeometry.Scheme.Modules} (sheaves of $\mathcal O_X$-modules) and the \lstinline{SheafOfModules.QuasicoherentData} typeclass for quasi-coherence. The combination "invertible quasi-coherent sheaf" is not pre-packaged; it is the content of this definition.
26	\end{remark}
27	
28	\section{Group structure under tensor product}
29	
30	% NOTE: Iter-003 closed this under the global-sections approximation: the Lean
31	% instance is `inferInstanceAs (CommGroup (CommRing.Pic _))`. Tensor-product /
32	% dual sheaf interpretation is correct on affine schemes; for non-affine schemes
33	% the realisation differs from the informal proof below (which describes the
34	% sheaf-level construction). See def:Scheme_LineBundle's % NOTE.
35	\begin{theorem}[Picard group of a scheme]
36	  \label{thm:Scheme_Pic_commGroup}
37	  \lean{AlgebraicGeometry.Scheme.instCommGroupLineBundle}
38	  For every scheme $X$, the type of line bundles on $X$ (modulo isomorphism) carries a canonical commutative-group structure. The operation is tensor product over $\mathcal O_X$, the unit is the structure sheaf $\mathcal O_X$ itself, and the inverse of a line bundle $L$ is its $\mathcal O_X$-dual $L^\vee = \mathcal{H}om_{\mathcal O_X}(L, \mathcal O_X)$.
39	
40	  We denote this group by $\Pic(X)$ and call it the \emph{Picard group} of $X$.
41	\end{theorem}
42	
43	\begin{proof}
44	  \uses{def:Scheme_LineBundle}
45	  Tensor product of two invertible quasi-coherent sheaves is invertible quasi-coherent (locally on $X$ this reduces to the corresponding statement for invertible modules over commutative rings, which Mathlib has via \lstinline{Module.Invertible}). The structure sheaf is the tensor unit. The dual sheaf is the inverse: $L \otimes_{\mathcal O_X} L^\vee \cong \mathcal O_X$ canonically. Commutativity and associativity descend from the symmetric monoidal structure on $X.\mathtt{Modules}$.
46	\end{proof}
47	
48	\section{Pull-back functoriality}
49	
50	% NOTE: Iter-003 closed this under the global-sections approximation, with
51	% pull-back realised as `CommRing.Pic.mapRingHom (f.app ⊤).hom` rather than the
52	% sheaf-pull-back `f^* L = f^{-1}L ⊗_{f^{-1} O_Y} O_X` of the informal proof.
53	% Functoriality (pullback_id, pullback_comp) is fully formalised. See
54	% def:Scheme_LineBundle's % NOTE.
55	\begin{theorem}[Pull-back of line bundles]
56	  \label{thm:Scheme_Pic_pullback}
57	  \lean{AlgebraicGeometry.Scheme.Pic.pullback}
58	  Let $f \colon X \to Y$ be a morphism of schemes. Pull-back of $\mathcal O_Y$-modules along $f$ restricts to a group homomorphism
59	  \[
60	    f^* \colon \Pic(Y) \;\to\; \Pic(X),\qquad L \;\mapsto\; f^* L \;:=\; f^{-1} L \otimes_{f^{-1}\mathcal O_Y} \mathcal O_X.
61	  \]
62	  Pull-back preserves invertibility, commutes with tensor product, and is functorial: $(\mathrm{id}_X)^* = \mathrm{id}_{\Pic(X)}$ and $(f \circ g)^* = g^* \circ f^*$.
63	\end{theorem}
64	
65	\begin{proof}
66	  \uses{thm:Scheme_Pic_commGroup}
67	  Mathlib has \lstinline{ModuleCat.tensorObj} for the tensor product of $\mathcal O_X$-modules and the pullback of sheaves of modules along a scheme morphism. Pull-back commutes with tensor product (\lstinline{Mathlib/CategoryTheory/Monoidal/Functor.lean} for the abstract statement; the geometric instance is the content of the theorem). Functoriality is the standard sheaf-pullback functoriality.
68	\end{proof}
69	
70	\section{Use in the project}
71	
72	The Picard group $\Pic(X)$ is the underlying \emph{set} (modulo isomorphism) of the Picard \emph{scheme} $\Pic_{C/k}$ in the curve case; the scheme structure adds a $k$-scheme of finite type representing the relative Picard functor $S \mapsto \Pic(C \times_k S) / \Pic(S)$.
