204	\begin{definition}[Sheaf cohomology with $\ModuleCat k$ coefficients]
205	  \label{def:Scheme_HModule}
206	  \lean{AlgebraicGeometry.Scheme.HModule}
207	  \uses{thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
208	  Let $k$ be a field, $C$ a category with $J : \mathrm{GrothendieckTopology}\,C$, and assume $\HasSheafify\,J\,(\ModuleCat\,k)$ and $\HasExt(\Sheaf(J, \ModuleCat\,k))$. For $F : \Sheaf(J, \ModuleCat\,k)$ and $n \in \mathbb N$, define the $\ModuleCat k$-flavoured sheaf cohomology
209	  \[
210	    \mathtt{HModule}\,k\,F\,n \;:=\; \Ext\bigl((\mathtt{constantSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k),\ F,\ n\bigr),
211	  \]
212	  where $\Ext$ is the standard \lstinline{CategoryTheory.Abelian.Ext} construction. This is automatically a $\Module k$-module via \lstinline{Abelian.Ext.instModule}.
213	\end{definition}
