289	  \label{def:Scheme_cechCohomology_OC}
290	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC}
291	  \uses{def:Scheme_cechCochain_OC}
292	  With $(C, \mathcal U)$ as in Definition~\ref{def:Scheme_cechCochain_OC}, define for each $n : \mathbb N$
293	  \[
294	    \mathtt{cechCohomology\_OC}\,(C)(\mathcal U)(n) \;:=\; \bigl(\mathtt{cechCochain\_OC}\,(C)(\mathcal U)\bigr).\mathtt{homology}\,n \;\in\; \ModuleCat.\{u\}\,k.
295	  \]
296	\end{definition}
297	
298	\begin{proof}
299	  \uses{def:Scheme_cechCochain_OC}
300	  Direct application of \lstinline{HomologicalComplex.homology} on the cochain complex of Definition~\ref{def:Scheme_cechCochain_OC}. The closure body is the one-line term \lstinline{(Scheme.cechCochain_OC C 𝒰).homology n}.
301	\end{proof}
