26	\section{$\Ext$ for $\ModuleCat k$-valued sheaves on opens}
27	\label{sec:moduleK_ext}
28	
29	\begin{theorem}[$\Ext$ on the topology of opens, $\ModuleCat k$-valued]
30	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
31	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
32	  \uses{thm:HasSheafify_Opens_ModuleCatK}
33	  Let $k$ be a commutative ring and $X$ a topological space. Then the category $\Sheaf(\opens(X), \ModuleCat k)$ has
34	  \[
