44	\section{The structure sheaf of a $\Spec k$-scheme as a sheaf of $k$-modules}
45	\label{sec:scheme_toModuleKSheaf}
46	
47	This section provides the substantive content of Phase~A step~5: for $C : \Over\,(\Spec\,(\CommRingCat\,k))$, equipping the structure sheaf $\struct C$ with a sheaf-of-$k$-modules structure via the algebra map induced by the structure morphism $C.\mathrm{hom} : C.\mathrm{left} \to \Spec\,(\CommRingCat\,k)$. Together with the typeclass plumbing of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} and Mathlib's \lstinline{CategoryTheory.Abelian.Ext.instModule}, this completes the typeclass chain that gives $H^1(C, \struct C)$ a $\Module k$ structure.
48	
49	\subsection{The algebra map from the structure morphism}
50	
51	For each open $U \subseteq C.\mathrm{left}$, the structure morphism induces a chain of ring maps
52	\[
53	  k \xrightarrow{(\Gamma\!\Spec\!\mathrm{Iso}\,k)^{-1}} \Gamma(\Spec\,k, \top) \xrightarrow{C.\mathrm{hom}.\mathrm{app}\,\top} \Gamma(C.\mathrm{left}, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C.\mathrm{left}, U),
54	\]
55	where $\rho$ is the restriction along $U \le C.\mathrm{hom}^{-1}\top = \top$. Mathlib's \lstinline{Scheme.\Gamma SpecIso} provides the first iso, and the rest is the ordinary \lstinline{Scheme.Hom.app} together with the action of the presheaf on the inclusion $U \le \top$.
56	
57	\begin{definition}[Algebra map on a section]
58	  \label{def:Scheme_kToSection}
59	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
60	  \uses{def:Scheme_toAbSheaf}
61	  Let $k$ be a commutative ring and $C : \Over\,(\Spec\,(\CommRingCat\,k))$. For any open $U$ of $C.\mathrm{left}$, define
62	  \[
63	    \mathtt{kToSection}\,C\,U \;\colon\; \CommRingCat\,k \;\longrightarrow\; \Gamma(C.\mathrm{left}, U)
64	  \]
65	  to be the composition $(\Gamma\!\Spec\!\mathrm{Iso}\,(\CommRingCat\,k))^{-1} \circ (C.\mathrm{hom}.\mathrm{app}\,\top) \circ \rho$, where $\rho$ is the restriction map of $C.\mathrm{left}$ from $\top$ to $U$.
66	\end{definition}
67	
68	\begin{definition}[Algebra structure on a section]
69	  \label{def:Scheme_algebraSection}
70	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
71	  \uses{def:Scheme_kToSection}
72	  The ring map $\mathtt{kToSection}\,C\,U$ exhibits $\Gamma(C.\mathrm{left}, U)$ as a $k$-algebra. We register the resulting $\Algebra\,k\,(\Gamma(C.\mathrm{left}, U))$ instance via \lstinline{RingHom.toAlgebra}.
73	\end{definition}
74	
75	\begin{lemma}[Defining identity for the algebra map]
76	  \label{lem:Scheme_algebraMap_eq_kToSection}
77	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
78	  \uses{def:Scheme_algebraSection}
79	  Under the algebra structure of Definition~\ref{def:Scheme_algebraSection},
80	  \[
81	    \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U)) \;=\; (\mathtt{kToSection}\,C\,U).\mathrm{hom}.
82	  \]
83	\end{lemma}
84	
85	\begin{proof}
86	  \uses{def:Scheme_algebraSection}
87	  Definitionally true: \lstinline{RingHom.toAlgebra}$\,(f).\mathrm{algebraMap} = f$.
88	\end{proof}
89	
90	\subsection{Naturality of the algebra map}
91	
92	\begin{lemma}[Restriction is compatible with the algebra map]
93	  \label{lem:Scheme_kToSection_naturality}
94	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
95	  \uses{def:Scheme_kToSection}
96	  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ (i.e.\ $V \le U$ in $\opens(C.\mathrm{left})$),
97	  \[
98	    \mathtt{kToSection}\,C\,U \,\circ\, C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f \;=\; \mathtt{kToSection}\,C\,V.
99	  \]
100	\end{lemma}
101	
102	\begin{proof}
103	  \uses{def:Scheme_kToSection}
104	  Both sides factor through $C.\mathrm{hom}.\mathrm{app}\,\top : \Gamma(\Spec k, \top) \to \Gamma(C.\mathrm{left}, \top)$. The remaining triangle on $\opens(C.\mathrm{left})$ commutes by functoriality of $C.\mathrm{left}.\mathtt{presheaf}$ on the composable inclusions $V \le U \le \top$.
105	\end{proof}
106	
107	\begin{lemma}[Algebra-map naturality]
108	  \label{lem:Scheme_algebraMap_naturality}
109	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
110	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
111	  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ and $r \in k$,
112	  \[
113	    (C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f).\mathrm{hom}\bigl(\mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U))\,r\bigr) \;=\; \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, V))\,r.
114	  \]
115	\end{lemma}
116	
117	\begin{proof}
118	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
119	  Lemma~\ref{lem:Scheme_algebraMap_eq_kToSection} reduces both sides to the underlying ring map of $\mathtt{kToSection}$; Lemma~\ref{lem:Scheme_kToSection_naturality} then closes the goal by congruence.
120	\end{proof}
121	
122	\subsection{The presheaf of $k$-modules and its sheaf condition}
123	
124	\begin{definition}[Presheaf of $k$-modules from $\struct C$]
125	  \label{def:Scheme_toModuleKPresheaf}
126	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf}
127	  \uses{def:Scheme_algebraSection, lem:Scheme_algebraMap_naturality}
128	  Define the presheaf
129	  \[
130	    \mathtt{toModuleKPresheaf}\,C \;\colon\; \opens(C.\mathrm{left})^{\mathrm{op}} \;\longrightarrow\; \ModuleCat\,k
131	  \]
132	  by
133	  \[
134	    \mathtt{toModuleKPresheaf}\,C \,.\,\mathrm{obj}\,U \;:=\; \ModuleCat.\mathrm{of}\,k\,(\Gamma(C.\mathrm{left}, U)),
135	  \]
136	  with the action of $k$ given by the algebra structure of Definition~\ref{def:Scheme_algebraSection}, and on a morphism $f : U \to V$ by the restriction map $(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f).\mathrm{hom}$, viewed as a $k$-linear map. The action on morphisms is well-defined because the underlying ring map preserves $+$ and is $k$-linear by the naturality lemma~\ref{lem:Scheme_algebraMap_naturality}: $\rho(\mathtt{algebraMap}\,r \cdot x) = \rho(\mathtt{algebraMap}\,r) \cdot \rho(x) = \mathtt{algebraMap}\,r \cdot \rho(x)$. Functoriality reduces to $C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map\_id}$ and \lstinline{map_comp}.
137	\end{definition}
138	
139	\begin{theorem}[Sheaf condition]
140	  \label{thm:Scheme_toModuleKPresheaf_isSheaf}
141	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_isSheaf}
142	  \uses{def:Scheme_toModuleKPresheaf, thm:HasSheafify_Opens_ModuleCatK}
143	  $\mathtt{toModuleKPresheaf}\,C$ is a sheaf for the Grothendieck topology $\Opens.\mathrm{grothendieckTopology}\,C.\mathrm{left}.\mathrm{toTopCat}$.
144	\end{theorem}
145	
146	\begin{proof}
147	  \uses{def:Scheme_toModuleKPresheaf}
148	  By the concrete-category criterion \lstinline{Presheaf.isSheaf_iff_isSheaf_forget} applied to the forgetful functor $\ModuleCat\,k \to \Type$, it suffices to show that $\mathtt{toModuleKPresheaf}\,C \,\circ\, \mathrm{forget}\,(\ModuleCat\,k)$ is a sheaf in $\Type$. By construction, this composite agrees on objects and morphisms with $C.\mathrm{left}.\mathtt{presheaf} \,\circ\, \mathrm{forget}\,\CommRingCat$. The latter is a sheaf in $\Type$ because $C.\mathrm{left}.\mathtt{sheaf}$ is a sheaf in $\CommRingCat$ and \lstinline{Presheaf.isSheaf_iff_isSheaf_forget} also applies on the $\CommRingCat$ side.
149	\end{proof}
