471	\end{theorem}
472	
473	\begin{proof}
474	  \uses{thm:Scheme_IsAffineHModuleVanishing}
475	  Direct application of the class field. The hypothesis \lstinline{IsAffineHModuleVanishing.subsingleton_HModule' hU i hi} produces \lstinline{Subsingleton (HModule' k F i U)}; \lstinline{Module.Finite} over a subsingleton is automatic in Mathlib (any subsingleton module is generated by the empty set, hence finitely generated and finitely presented). The combined body is \lstinline{have : Subsingleton _ := IsAffineHModuleVanishing.subsingleton_HModule' (F := F) hU i hi; inferInstance}.
476	\end{proof}
