714	\begin{lemma}[Linear lifting of \texttt{left\_adjoint\_additive}]
715	  \label{lemma:Adjunction_left_adjoint_linear}
716	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
717	  Let $F : \mathcal{C} \to \mathcal{D}$ be a functor between $R$-linear preadditive categories with right adjoint $G$. If $G$ is $R$-linear (and additive), then $F$ is $R$-linear.
718	\end{lemma}
719	
720	\begin{proof}
721	  Mirrors Mathlib's \lstinline{left_adjoint_additive}. By $\mathtt{homEquiv}$-injectivity, $F.\mathtt{map}\,(r \cdot f) = r \cdot F.\mathtt{map}\,f$ reduces to an equality on the right side of the adjunction, where $\mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$ rewrites both sides via unit naturality and the default simp lemmas \lstinline{Linear.smul_comp} and \lstinline{Linear.comp_smul}.
722	\end{proof}
