724	\begin{lemma}[Right-adjoint version]
725	  \label{lemma:Adjunction_right_adjoint_linear}
726	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
727	  Dual of Lemma~\ref{lemma:Adjunction_left_adjoint_linear}: if $F$ is $R$-linear (and additive), then $G$ is $R$-linear.
728	\end{lemma}
729	
730	\begin{proof}
731	  Same proof shape, using $\mathtt{adj.homEquiv\_counit}$ in place of $\mathtt{adj.homEquiv\_unit}$.
