735	  \label{def:Adjunction_homLinearEquiv}
736	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
737	  \uses{lemma:Adjunction_left_adjoint_linear}
738	  Let $\mathtt{adj} : F \dashv G$ between $R$-linear preadditive categories with $F.\mathtt{Additive}$, $G.\mathtt{Additive}$, $G.\mathtt{Linear}\,R$. Then for all objects $X$ and $Y$, the additive equivalence $\mathtt{adj.homAddEquiv}\,X\,Y$ upgrades to a $\LinearEquiv$ over $R$:
739	  \[
740	    (F.\mathtt{obj}\,X \to Y) \;\equivl{R}\; (X \to G.\mathtt{obj}\,Y).
741	  \]
742	\end{theorem}
