750	\begin{theorem}[Constant-sheaf / global-sections $\LinearEquiv$]
751	  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
752	  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
753	  \uses{def:Adjunction_homLinearEquiv}
