755	  \[
756	    ((\mathtt{constantSheaf}\,J\,\_).\mathtt{obj}\,X \to F) \;\equivl{k}\; (X \to (\Sheaf.\Gamma\,J\,\_).\mathtt{obj}\,F).
757	  \]
