901	  \label{thm:Scheme_subsingleton_HModule'_supr_of_isCechAcyclicCover}
902	  \lean{AlgebraicGeometry.Scheme.subsingleton_HModule'_supr_of_isCechAcyclicCover}
903	  \uses{def:Scheme_IsCechAcyclicCover, def:Scheme_HModule'}
