1	\chapter{Sheaves of $k$-modules: sheafification, Ext, and the structure sheaf as a sheaf of $k$-modules}
2	\label{chap:Cohomology_StructureSheafModuleK}
3	
4	This chapter implements Phase~A step~5: equipping $H^1(C, \mathcal O_C)$ with a $k$-vector-space structure when $C$ is a scheme over $\Spec k$. The route is through the linear enrichment of the sheaf category over $k$, which automatically provides a $k$-module structure on $\Ext$ groups in any $k$-linear abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of $H^1(C, \mathcal O_C)$ in Definition~\ref{def:genus}.
5	
6	The chapter splits into two parts. Sections~\ref{sec:moduleK_prereqs}--\ref{sec:moduleK_ext} provide the typeclass plumbing: sheafification and $\Ext$ for sheaves valued in $k$-modules. Section~\ref{sec:scheme_toModuleKSheaf} provides the substantive content: the $k$-module-valued structure sheaf for a scheme over $\Spec k$, built from the algebra map induced by the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of genus is Phase~A step~6 (Serre finiteness, multi-iteration).
7	
8	\section{Sheafification of $k$-module-valued sheaves on opens}
9	\label{sec:moduleK_prereqs}
10	
11	\begin{theorem}[Sheafification on the topology of opens, $k$-module valued]
12	  \label{thm:HasSheafify_Opens_ModuleCatK}
13	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
14	  Let $k$ be a commutative ring and $X$ a topological space. Then the Grothendieck topology of opens of $X$ admits sheafification for sheaves valued in the category of $k$-modules.
15	\end{theorem}
16	
17	\begin{proof}
18	  Mathlib's general sheafification API constructs sheafification whenever weak sheafification holds and the resulting sheafification preserves finite limits. For the topology of opens and the category of $k$-modules, both prerequisites are available in Mathlib. The instance is therefore inferable; the formal task is the universe pinning, mirroring the abelian-group analogue (Theorem~\ref{thm:HasSheafify_Opens_AddCommGrp}).
19	\end{proof}
20	
21	\section{$\Ext$ for $k$-module-valued sheaves on opens}
22	\label{sec:moduleK_ext}
23	
24	\begin{theorem}[$\Ext$ on the topology of opens, $k$-module valued]
25	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
26	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
27	  \uses{thm:HasSheafify_Opens_ModuleCatK}
28	  Let $k$ be a commutative ring and $X$ a topological space. Then the category of sheaves of $k$-modules on the topology of opens of $X$ admits $\Ext$ groups.
29	\end{theorem}
30	
31	\begin{proof}
32	  The category of $k$-modules is abelian. The sheaf category inherits an abelian structure from an abelian value category once sheafification is available (Theorem~\ref{thm:HasSheafify_Opens_ModuleCatK}). Mathlib's standard construction produces $\Ext$ from any abelian category. The universe annotation matches the morphism universe of the sheaf category, mirroring the abelian-group analogue (Theorem~\ref{thm:HasExt_Sheaf_Opens_AddCommGrp}).
33	\end{proof}
34	
35	\section{The structure sheaf of a $\Spec k$-scheme as a sheaf of $k$-modules}
36	\label{sec:scheme_toModuleKSheaf}
37	
38	This section provides the substantive content of Phase~A step~5. For $C$ a scheme over $\Spec k$, the structure morphism $C \to \Spec k$ induces an algebra map $k \to \Gamma(C, U)$ for every open $U \subseteq C$. This equips the structure sheaf with a sheaf-of-$k$-modules structure.
39	
40	\subsection{The algebra map from the structure morphism}
41	
42	For each open $U \subseteq C$, the structure morphism induces a chain of ring maps
43	\[
44	  k \xrightarrow{\cong} \Gamma(\Spec k, \top) \xrightarrow{C.\mathrm{hom}} \Gamma(C, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C, U),
45	\]
46	where $\rho$ is the restriction along $U \le C.\mathrm{hom}^{-1}\top = \top$.
47	
48	\begin{definition}[Algebra map on a section]
49	  \label{def:Scheme_kToSection}
50	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
51	  \uses{def:Scheme_toAbSheaf}
52	  Let $k$ be a commutative ring and $C$ a scheme over $\Spec k$. For any open $U$ of $C$, define the ring map $k \to \Gamma(C, U)$ to be the composition of the inverse of the canonical isomorphism $\Gamma(\Spec k, \top) \cong k$, the structure morphism map on global sections, and the restriction from $\top$ to $U$.
53	\end{definition}
54	
55	\begin{definition}[Algebra structure on a section]
56	  \label{def:Scheme_algebraSection}
57	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
58	  \uses{def:Scheme_kToSection}
59	  The ring map of Definition~\ref{def:Scheme_kToSection} exhibits $\Gamma(C, U)$ as a $k$-algebra.
60	\end{definition}
61	
62	\begin{lemma}[Defining identity for the algebra map]
63	  \label{lem:Scheme_algebraMap_eq_kToSection}
64	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
65	  \uses{def:Scheme_algebraSection}
66	  Under the algebra structure of Definition~\ref{def:Scheme_algebraSection}, the structure map $k \to \Gamma(C, U)$ equals the ring map of Definition~\ref{def:Scheme_kToSection}.
67	\end{lemma}
68	
69	\begin{proof}
70	  \uses{def:Scheme_algebraSection}
71	  Definitionally true: converting a ring homomorphism to an algebra structure and extracting the structure map recovers the original homomorphism.
72	\end{proof}
73	
74	\subsection{Naturality of the algebra map}
75	
76	\begin{lemma}[Restriction is compatible with the algebra map]
77	  \label{lem:Scheme_kToSection_naturality}
78	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
79	  \uses{def:Scheme_kToSection}
80	  For any inclusion $V \le U$ of opens in $C$, the algebra map commutes with restriction: the composition $k \to \Gamma(C, U) \to \Gamma(C, V)$ equals the direct map $k \to \Gamma(C, V)$.
81	\end{lemma}
82	
83	\begin{proof}
84	  \uses{def:Scheme_kToSection}
85	  Both sides factor through the structure morphism map on global sections. The remaining triangle commutes by functoriality of the presheaf on composable inclusions.
86	\end{proof}
87	
88	\begin{lemma}[Algebra-map naturality]
89	  \label{lem:Scheme_algebraMap_naturality}
90	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
91	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
92	  For any inclusion $V \le U$ of opens in $C$ and any $r \in k$, the restriction map sends the image of $r$ in $\Gamma(C, U)$ to the image of $r$ in $\Gamma(C, V)$.
93	\end{lemma}
94	
95	\begin{proof}
96	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
97	  Lemma~\ref{lem:Scheme_algebraMap_eq_kToSection} reduces both sides to the underlying ring map of the algebra map; Lemma~\ref{lem:Scheme_kToSection_naturality} then closes the goal by congruence.
98	\end{proof}
