  \label{thm:Scheme_AffineCoverMVSquare_finrank_HModule_eq_HModule_prime_X4_curve}
  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare.finrank_HModule_eq_HModule'_X₄_curve}
