1	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with $k$-module coefficients}
2	\label{chap:Cohomology_MayerVietoris}
3	
4	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in $k$-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers $H^n(X,\mathcal F)$ and $H^{\prime n}(U,\mathcal F)$ live in Chapter~\ref{chap:Cohomology_StructureSheafModuleK} and are imported here.
5	
6	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of $H^1(C,\mathcal O_C)$ in Definition~\ref{def:genus}.
7	
8	\section{Functoriality of cohomology in the open variable}
9	\label{sec:hmodule_prime_cohomologyPresheaf}
10	
11	The cohomology-of-an-open carrier $H^{\prime n}(X,\mathcal F)$ is contravariantly functorial in the open variable $X$. Assembling this functoriality yields a presheaf
12	\[
13	  X \longmapsto H^{\prime n}(X, \mathcal F),
14	\]
15	and, varying $\mathcal F$ as well, a bifunctor from sheaves of $k$-modules to presheaves of abelian groups. The codomain is the category of abelian groups because $\Ext$ is always valued there, regardless of the linear enrichment of the source category; the per-fiber $k$-module structure is inherited from the reducible wrapper on $H^{\prime n}$.
16	
17	\begin{definition}[Cohomology presheaf functor, $H'$ flavor]
18	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
19	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
20	  \uses{def:Scheme_HModule_prime, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
21	  Let $k$ be a field, $C$ a category equipped with a Grothendieck topology $J$, and assume sheafification and $\Ext$ exist for sheaves of $k$-modules on $J$. For $n \in \mathbb N$, define the cohomology presheaf functor
22	  \[
23	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
24	  \]
25	  by the standard composition of the Yoneda embedding, the free-$k$-module functor, sheafification, and the $n$-th $\Ext$ functor.
26	\end{definition}
27	
28	\begin{proof}
29	  \uses{def:Scheme_HModule_prime}
30	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
31	\end{proof}
32	
33	\begin{definition}[Cohomology presheaf, $H'$ flavor]
34	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
35	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
36	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
37	  In the setting of Definition~\ref{def:Scheme_HModule_prime_cohomologyPresheafFunctor}, let $\mathcal F$ be a sheaf of $k$-modules. For $n \in \mathbb N$, define the cohomology presheaf
38	  \[
39	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
40	  \]
41	  to be the evaluation of the bifunctor at $\mathcal F$.
42	\end{definition}
43	
44	\begin{proof}
45	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
46	  Direct evaluation of the bifunctor at $\mathcal F$.
47	\end{proof}
48	
49	\begin{remark}
50	  For every object $X$ of $C$, the underlying type of $\mathcal H^{\prime n}(\mathcal F)(X)$ is definitionally equal to $H^{\prime n}(X, \mathcal F)$. The per-fiber $k$-module structure is therefore inherited through the $H'$ wrapper.
51	\end{remark}
52	
53	\begin{remark}[Lean implementation]
54	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level $H'$ carrier.
55	\end{remark}
56	
57	\section{Mayer--Vietoris long exact sequence}
58	\label{sec:hmodule_prime_mayer_vietoris}
59	
60	A Mayer--Vietoris square for a Grothendieck topology $J$ on a category $C$ is a pullback square
61	\[
62	  \begin{tikzcd}
63	    X_1 \ar[r] \ar[d] & X_2 \ar[d] \\
64	    X_3 \ar[r] & X_4
65	  \end{tikzcd}
66	\]
67	that is a $J$-cover: the pair of morphisms $X_2 \to X_4$ and $X_3 \to X_4$ is a covering family, and $X_1$ is the pullback. For a sheaf $\mathcal F$, the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
68	
69	\subsection{The restriction maps}
70	
71	\begin{definition}[Sum of two restriction maps]
72	  \label{def:Scheme_HModule_prime_toBiprod}
73	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
74	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
75	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
76	  \[
77	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
78	  \]
79	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.
80	\end{definition}
81	
82	\begin{proof}
83	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
84	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
85	\end{proof}
86	
87	\begin{definition}[Difference of two restriction maps]
88	  \label{def:Scheme_HModule_prime_fromBiprod}
89	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
90	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
91	  In the same setting, define the morphism
92	  \[
93	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
94	  \]
95	  to be the biproduct desc of the restriction map $X_1 \to X_2$ and the additive inverse of the restriction map $X_1 \to X_3$.
96	\end{definition}
97	
98	\begin{proof}
99	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
100	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.

