\begin{definition}[Split epi from an injective index map]
  \label{def:Scheme_splitEpi_pi_lift_of_injective}
  \lean{AlgebraicGeometry.Scheme.splitEpi_pi_lift_of_injective}
  Let $\{M_\alpha\}_{\alpha \in A}$ be a family of $k$-modules and $f : B \to A$ an injective function. Then the canonical projection
  \[
    \prod_{\alpha \in A} M_\alpha \longrightarrow \prod_{\beta \in B} M_{f(\beta)}
  \]
  admits a section, hence is a split epimorphism in the category of $k$-modules.
\end{definition}

\begin{proof}
  Choose a retraction of $f$ (possible because $B$ injects into $A$), extend families on $B$ to families on $A$ by the chosen values on the complement, and verify the section identity pointwise.
\end{proof}

\begin{theorem}[From exactness of cochains to vanishing of Čech cohomology]
  \label{thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt}
  \lean{AlgebraicGeometry.Scheme.cechCohomology_subsingleton_of_cechCochain_exactAt}
  Let $\mathcal F$ be a sheaf of $k$-modules on a $k$-scheme $X$, let $\mathfrak U = \{\mathcal U_i\}$ be an open cover, and let $n \ge 1$. If the Čech cochain complex of $\mathcal F$ with respect to $\mathfrak U$ is exact at degree $n$, then the Čech cohomology group $\check H^n(\mathfrak U, \mathcal F)$ is a subsingleton.
\end{theorem}

\begin{proof}
  Exactness at degree $n$ means that the $n$-cocycles equal the $n$-coboundaries, so the quotient $\check H^n$ has at most one element.
\end{proof}

